+    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
+    enum AuthState {
+        Authenticated,
+        Unauthenticated,
+    }
+
+    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
+    enum CommandAuthClass {
+        NoAuthExempt,
